CREATE MATERIALIZED VIEW public.logins_mv AS
 SELECT l.id AS login_id,
    plc.profiles_id AS profile_id,
    l.session_id,
    l.created_at,
    l.active,
    l.mcp,
    l.generated
   FROM (public.logins_entry l
     LEFT JOIN public.profiles_logins_connection plc ON (((plc.login_id = l.id) AND (plc.active = true))))
  WITH NO DATA;


